// OutputResponseRegion - The SentinelOne region to send events to. In most cases you can find the region by either looking at your SentinelOne URL or knowing what geographic region your SentinelOne instance is contained in.
type OutputResponseRegion string

const (
	OutputResponseRegionUs     OutputResponseRegion = "US"
	OutputResponseRegionCa     OutputResponseRegion = "CA"
	OutputResponseRegionEmea   OutputResponseRegion = "EMEA"
	OutputResponseRegionAp     OutputResponseRegion = "AP"
	OutputResponseRegionAps    OutputResponseRegion = "APS"
	OutputResponseRegionAu     OutputResponseRegion = "AU"
	OutputResponseRegionCustom OutputResponseRegion = "Custom"
)

func (e OutputResponseRegion) ToPointer() *OutputResponseRegion {
	return &e
}

// IsExact returns true if the value matches a known enum value, false otherwise.
func (e *OutputResponseRegion) IsExact() bool {
	if e != nil {
		switch *e {
		case "US", "CA", "EMEA", "AP", "APS", "AU", "Custom":
			return true
		}
	}
	return false
}

